            } catch (e: IllegalArgumentException) {
                _uiState.update { SettingsUiState.Error("Failed to save settings: ${e.message}") }
            } catch (e: IllegalStateException) {
                _uiState.update { SettingsUiState.Error("Failed to save settings: ${e.message}") }
            }
        }
    }
}

